'use strict';
const $ = (sel, ctx = document) => ctx.querySelector(sel);
const $$ = (sel, ctx = document) => [...ctx.querySelectorAll(sel)];
(function initSlider() {
  const wrap     = $('.slider-wrap');
  const track    = $('#sliderTrack');
  const prevBtn  = $('#sliderPrev');
  const nextBtn  = $('#sliderNext');
  const dotsWrap = $('#sliderDots');
  if (!track || !prevBtn || !nextBtn) return;
  const items = $$('.slider-item', track);
  const total = items.length;
  if (total === 0) return;
  let current   = 0;
  let autoTimer = null;
  if (dotsWrap) {
    items.forEach((_, i) => {
      const dot = document.createElement('button');
      dot.type = 'button';
      dot.className = 'slider-dot' + (i === 0 ? ' active' : '');
      dot.setAttribute('aria-label', `${i + 1}. fotoğrafa git`);
      dot.addEventListener('click', () => goTo(i));
      dotsWrap.appendChild(dot);
    });
  }
  function updateDots() {
    if (!dotsWrap) return;
    $$('.slider-dot', dotsWrap).forEach((dot, i) => {
      dot.classList.toggle('active', i === current);
    });
  }
  const fillEl     = document.getElementById('sliderProgressFill');
  const counterEl  = document.getElementById('sliderCounter');
  const thumbsWrap = document.getElementById('sliderThumbs');
  const thumbBtns  = thumbsWrap ? $$('.slider-thumb', thumbsWrap) : [];
  thumbBtns.forEach((btn, i) => {
    btn.addEventListener('click', () => { goTo(i); startAuto(); });
  });
  function updateThumbs() {
    if (!thumbBtns.length) return;
    thumbBtns.forEach((btn, i) => btn.classList.toggle('active', i === current));
    if (thumbsWrap && thumbBtns[current]) {
      const btn = thumbBtns[current];
      const target = btn.offsetLeft - thumbsWrap.clientWidth / 2 + btn.offsetWidth / 2;
      thumbsWrap.scrollTo({ left: target, behavior: 'smooth' });
    }
  }
  function goTo(index) {
    current = ((index % total) + total) % total;
    track.style.transform = `translateX(-${current * 100}%)`;
    updateDots();
    updateThumbs();
    if (fillEl)    fillEl.style.width = ((current + 1) / total * 100) + '%';
    if (counterEl) counterEl.textContent = (current + 1) + ' / ' + total;
    items.forEach((item, i) => {
      item.setAttribute('aria-hidden', i !== current ? 'true' : 'false');
    });
  }
  function startAuto() {
    clearInterval(autoTimer);
    autoTimer = setInterval(() => goTo(current + 1), 4500);
  }
  function stopAuto() {
    clearInterval(autoTimer);
  }
  prevBtn.addEventListener('click', () => { goTo(current - 1); startAuto(); });
  nextBtn.addEventListener('click', () => { goTo(current + 1); startAuto(); });
  if (wrap) {
    wrap.addEventListener('mouseenter', stopAuto);
    wrap.addEventListener('mouseleave', startAuto);
    wrap.addEventListener('focusin',    stopAuto);
    wrap.addEventListener('focusout',   startAuto);
  }
  let touchStartX = 0;
  let touchStartY = 0;
  let isDragging  = false;
  track.addEventListener('touchstart', e => {
    touchStartX = e.touches[0].clientX;
    touchStartY = e.touches[0].clientY;
    isDragging  = false;
  }, { passive: true });
  track.addEventListener('touchmove', e => {
    const dX = Math.abs(e.touches[0].clientX - touchStartX);
    const dY = Math.abs(e.touches[0].clientY - touchStartY);
    if (dX > dY && dX > 8) isDragging = true;
  }, { passive: true });
  track.addEventListener('touchend', e => {
    if (!isDragging) return;
    const diff = touchStartX - e.changedTouches[0].clientX;
    if (Math.abs(diff) > 50) {
      goTo(current + (diff > 0 ? 1 : -1));
      startAuto();
    }
  });
  if (wrap) {
    wrap.addEventListener('keydown', e => {
      if (e.key === 'ArrowLeft')  { goTo(current - 1); startAuto(); }
      if (e.key === 'ArrowRight') { goTo(current + 1); startAuto(); }
    });
  }
  goTo(0);
  startAuto();
  document.addEventListener('visibilitychange', () => {
    document.hidden ? stopAuto() : startAuto();
  });
})();
(function initReveal() {
  if (!('IntersectionObserver' in window)) return;
  const elements = $$('.room-card, .service-card, .attraction-card, .about-img, .stat');
  elements.forEach((el, i) => {
    el.style.opacity   = '0';
    el.style.transform = 'translateY(24px)';
    el.style.transition = `opacity 0.55s ease ${(i % 4) * 80}ms, transform 0.55s ease ${(i % 4) * 80}ms`;
  });
  const observer = new IntersectionObserver(entries => {
    entries.forEach(entry => {
      if (!entry.isIntersecting) return;
      entry.target.style.opacity   = '1';
      entry.target.style.transform = 'translateY(0)';
      observer.unobserve(entry.target);
    });
  }, { threshold: 0.12 });
  elements.forEach(el => observer.observe(el));
})();
(function initHeroRotator() {
  const slides = document.querySelectorAll('.hero-title--slide');
  if (slides.length < 2) return;
  let current = 0;
  setInterval(() => {
    slides[current].classList.remove('active');
    current = (current + 1) % slides.length;
    slides[current].classList.add('active');
  }, 5000);
})();
(function initHeroVideo() {
  var bg = document.getElementById('heroVideoBg');
  if (!bg) return;
  function loadVideo() {
    var v = document.createElement('video');
    v.className = 'hero-video';
    v.autoplay = true;
    v.muted = true;
    v.loop = true;
    v.playsInline = true;
    v.setAttribute('aria-hidden', 'true');
    v.poster = 'img/medos-beach-hotel-guzelcamli.webp';
    var s = document.createElement('source');
    s.src = 'video/hero_new.mp4';
    s.type = 'video/mp4';
    v.appendChild(s);
    v.addEventListener('canplay', function () {
      bg.parentNode.replaceChild(v, bg);
    }, { once: true });
    v.load();
  }
  if (document.readyState === 'complete') {
    setTimeout(loadVideo, 800);
  } else {
    window.addEventListener('load', function () { setTimeout(loadVideo, 800); });
  }
})();